/**
 * Registers a new block provided a unique name and an object defining its behavior.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/
 */
import { registerBlockType } from '@wordpress/blocks';

/**
 * Lets webpack process CSS, SASS or SCSS files referenced in JavaScript files.
 * All files containing `style` keyword are bundled together. The code used
 * gets applied both to the front of your site and to the editor.
 *
 * @see https://www.npmjs.com/package/@wordpress/scripts#using-css
 */
import './style.scss';

/**
 * Internal dependencies
 */
import Edit from './edit';
import save from './save';
import metadata from './block.json';

/**
 * Every block starts by registering a new block type definition.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/
 */
registerBlockType( metadata.name, {
	/**
	 * @see ./edit.js
	 */
	edit: Edit,

	/**
	 * @see ./save.js
	 */
	save,
} );

/**
 * The following styles get applied both on the front of your site
 * and in the editor.
 *
 * Replace them with your own styles or remove the file completely.
 */

.wp-block-telex-block-eyes-follow-cursor {
	display: flex;
	justify-content: center;
	align-items: center;
	padding: 40px 20px;
	min-height: 200px;
}

.eyes-container {
	display: flex;
	gap: 40px;
	align-items: center;
	justify-content: center;
}

.eye {
	position: relative;
	width: 120px;
	height: 120px;
	background: white;
	border-radius: 50%;
	border: 3px solid #333;
	overflow: hidden;
	box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
}

.eyeball {
	position: relative;
	width: 100%;
	height: 100%;
	display: flex;
	align-items: center;
	justify-content: center;
}

.pupil {
	width: 40px;
	height: 40px;
	background: #333;
	border-radius: 50%;
	position: relative;
	transition: transform 0.1s ease-out;
}

.pupil::after {
	content: '';
	position: absolute;
	width: 12px;
	height: 12px;
	background: white;
	border-radius: 50%;
	top: 8px;
	left: 8px;
}

.eyelid {
	position: absolute;
	top: -100%;
	left: 0;
	width: 100%;
	height: 100%;
	background: inherit;
	border-radius: 50%;
	border: 3px solid #333;
	transition: top 0.2s ease-in-out;
	z-index: 10;
}

.eye.winking .eyelid {
	top: 0;
}

@media (max-width: 768px) {
	.eye {
		width: 80px;
		height: 80px;
	}

	.pupil {
		width: 28px;
		height: 28px;
	}

	.pupil::after {
		width: 8px;
		height: 8px;
		top: 6px;
		left: 6px;
	}

	.eyes-container {
		gap: 30px;
	}
}

/**
 * The following styles get applied inside the editor only.
 *
 * Replace them with your own styles or remove the file completely.
 */

.wp-block-telex-block-eyes-follow-cursor {
	.eyes-preview-note {
		text-align: center;
		margin-top: 20px;
		color: #666;
		font-size: 14px;
		font-style: italic;
	}
}

/**
 * Use this file for JavaScript code that you want to run in the front-end
 * on posts/pages that contain this block.
 */

document.addEventListener('DOMContentLoaded', function() {
	const blocks = document.querySelectorAll('.wp-block-telex-block-eyes-follow-cursor');

	blocks.forEach(function(block) {
		const eyes = block.querySelectorAll('.eye');
		const pupils = block.querySelectorAll('.pupil');

		// Track mouse movement
		function handleMouseMove(event) {
			const mouseX = event.clientX;
			const mouseY = event.clientY;

			pupils.forEach(function(pupil) {
				const eye = pupil.closest('.eye');
				const eyeRect = eye.getBoundingClientRect();
				const eyeCenterX = eyeRect.left + eyeRect.width / 2;
				const eyeCenterY = eyeRect.top + eyeRect.height / 2;

				// Calculate angle between eye center and mouse
				const deltaX = mouseX - eyeCenterX;
				const deltaY = mouseY - eyeCenterY;
				const angle = Math.atan2(deltaY, deltaX);

				// Maximum distance pupil can move (radius of eye minus radius of pupil)
				const maxDistance = 30;

				// Calculate distance but cap it at maxDistance
				const distance = Math.min(
					maxDistance,
					Math.sqrt(deltaX * deltaX + deltaY * deltaY) / 10
				);

				// Calculate pupil position
				const pupilX = Math.cos(angle) * distance;
				const pupilY = Math.sin(angle) * distance;

				// Apply transform
				pupil.style.transform = 'translate(' + pupilX + 'px, ' + pupilY + 'px)';
			});
		}

		// Random winking
		function randomWink() {
			// Random interval between 3-8 seconds
			const nextWink = Math.random() * 5000 + 3000;

			setTimeout(function() {
				// Randomly choose left eye (0) or right eye (1) or both (2)
				const whichEye = Math.floor(Math.random() * 3);

				if (whichEye === 0 || whichEye === 2) {
					eyes[0].classList.add('winking');
					setTimeout(function() {
						eyes[0].classList.remove('winking');
					}, 200);
				}

				if (whichEye === 1 || whichEye === 2) {
					eyes[1].classList.add('winking');
					setTimeout(function() {
						eyes[1].classList.remove('winking');
					}, 200);
				}

				// Schedule next wink
				randomWink();
			}, nextWink);
		}

		// Start tracking mouse
		document.addEventListener('mousemove', handleMouseMove);

		// Start random winking
		randomWink();
	});
});
